import type { NotificationCategory } from "../db/entities/NotificationEntity.js";

export type SemanticNotificationKind =
  | "daily_brief"
  | "deep_dive"
  | "full_report"
  | "quick_check"
  | "new_ideas"
  | "market_news";

export type NotificationStatusTone = "info" | "success" | "warning";

export interface SemanticNotificationRequest {
  kind: SemanticNotificationKind;
  status?: NotificationStatusTone;
  title?: string | null;
  headline?: string | null;
  summary?: string | null;
  reasoning?: string | null;
  ticker?: string | null;
  batchId?: string | null;
  actionUrl?: string | null;
}

export interface ComposedNotification {
  kind: SemanticNotificationKind;
  category: NotificationCategory;
  status: NotificationStatusTone;
  title: string;
  body: string;
  ticker: string | null;
  batchId: string | null;
  actionUrl: string | null;
}

export interface WebNotificationRender {
  category: NotificationCategory;
  title: string;
  body: string;
  ticker: string | null;
  batchId: string | null;
}

export interface TelegramNotificationRender {
  text: string;
  parseMode: undefined;
  disableWebPagePreview: true;
}

export const MAX_COMPOSED_TITLE_LENGTH = 120;
export const MAX_COMPOSED_BODY_LENGTH = 700;
export const MAX_TELEGRAM_MESSAGE_LENGTH = 3600;

const STATUS_MARKERS: Record<NotificationStatusTone, string> = {
  info: "ℹ️",
  success: "✅",
  warning: "⚠️",
};

const CATEGORY_BY_KIND: Record<SemanticNotificationKind, NotificationCategory> = {
  daily_brief: "daily_brief",
  deep_dive: "report",
  full_report: "report",
  quick_check: "report",
  new_ideas: "report",
  market_news: "market_news",
};

const DEFAULT_TITLES: Record<SemanticNotificationKind, string> = {
  daily_brief: "Daily brief ready",
  deep_dive: "Deep-dive report ready",
  full_report: "Full report ready",
  quick_check: "Quick check ready",
  new_ideas: "New ideas ready",
  market_news: "Market news update",
};

const DEFAULT_BODIES: Record<SemanticNotificationKind, string> = {
  daily_brief: "Your daily brief is ready to review.",
  deep_dive: "A deep-dive report is ready to review.",
  full_report: "A full report is ready to review.",
  quick_check: "A quick-check report is ready to review.",
  new_ideas: "New report ideas are ready to review.",
  market_news: "Market update available.",
};

function normalizePlainText(value: string | null | undefined): string {
  return (value ?? "")
    .replace(/[\u0000-\u001f\u007f]/g, " ")
    .replace(/<\/?script\b[^>]*>/gi, " ")
    .replace(/[`*_~>#\[\]()]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function clip(value: string, maxLength: number): string {
  if (value.length <= maxLength) return value;
  const clipped = value.slice(0, Math.max(0, maxLength - 1)).trimEnd();
  return `${clipped}…`;
}

function normalizeTicker(value: string | null | undefined): string | null {
  const ticker = normalizePlainText(value).toUpperCase().replace(/[^A-Z0-9.-]/g, "");
  return ticker.length > 0 ? clip(ticker, 16) : null;
}

function normalizeOptional(value: string | null | undefined, maxLength: number): string | null {
  const normalized = normalizePlainText(value);
  return normalized.length > 0 ? clip(normalized, maxLength) : null;
}

function withTicker(title: string, ticker: string | null): string {
  if (!ticker || title.toUpperCase().includes(ticker)) return title;
  return `${title}: ${ticker}`;
}

function defaultStatus(kind: SemanticNotificationKind): NotificationStatusTone {
  return kind === "market_news" ? "info" : "success";
}

function selectBody(request: SemanticNotificationRequest, kind: SemanticNotificationKind): string {
  const summary = normalizePlainText(request.summary);
  if (summary.length > 0) return clip(summary, MAX_COMPOSED_BODY_LENGTH);

  const reasoning = normalizePlainText(request.reasoning);
  if (reasoning.length > 0) return clip(reasoning, MAX_COMPOSED_BODY_LENGTH);

  return DEFAULT_BODIES[kind];
}

export function composeNotification(request: SemanticNotificationRequest): ComposedNotification {
  const kind = request.kind;
  const ticker = normalizeTicker(request.ticker);
  const rawTitle = normalizePlainText(request.title) || normalizePlainText(request.headline) || DEFAULT_TITLES[kind];
  const title = clip(withTicker(rawTitle, ticker), MAX_COMPOSED_TITLE_LENGTH);

  return {
    kind,
    category: CATEGORY_BY_KIND[kind],
    status: request.status ?? defaultStatus(kind),
    title,
    body: selectBody(request, kind),
    ticker,
    batchId: normalizeOptional(request.batchId, 128),
    actionUrl: normalizeOptional(request.actionUrl, 300),
  };
}

function appendActionCue(body: string, actionUrl: string | null, maxLength: number): string {
  if (!actionUrl) return clip(body, maxLength);
  const cue = `Open: ${actionUrl}`;
  const separator = body.length > 0 ? "\n\n" : "";
  const availableBodyLength = Math.max(0, maxLength - separator.length - cue.length);
  return `${clip(body, availableBodyLength)}${separator}${cue}`.trim();
}

export function renderWebNotification(composed: ComposedNotification): WebNotificationRender {
  return {
    category: composed.category,
    title: clip(composed.title, MAX_COMPOSED_TITLE_LENGTH),
    body: appendActionCue(composed.body, composed.actionUrl, MAX_COMPOSED_BODY_LENGTH + 80),
    ticker: composed.ticker,
    batchId: composed.batchId,
  };
}

export function renderTelegramNotification(composed: ComposedNotification): TelegramNotificationRender {
  const marker = STATUS_MARKERS[composed.status];
  const title = clip(composed.title, MAX_COMPOSED_TITLE_LENGTH);
  const prefix = `${marker} ${title}`;
  const bodyLimit = Math.max(0, MAX_TELEGRAM_MESSAGE_LENGTH - prefix.length - 2);
  const body = appendActionCue(composed.body, composed.actionUrl, bodyLimit);

  return {
    text: clip(`${prefix}\n${body}`.trim(), MAX_TELEGRAM_MESSAGE_LENGTH),
    parseMode: undefined,
    disableWebPagePreview: true,
  };
}

import { promises as fs } from "fs";
import path from "path";
import { NotificationPreferencesSchema, type NotificationPreferences } from "../schemas/notifications.js";
import { resolveConfiguredPath } from "./paths.js";
import { logger } from "./logger.js";
import { getStoredWhatsAppConnection, getUserChannelConnectivity } from "./channelService.js";
import {
  composeNotification,
  renderTelegramNotification,
  renderWebNotification,
  type ComposedNotification,
  type SemanticNotificationRequest,
} from "./notificationComposer.js";
import {
  insertNotification as dbInsertNotification,
  updateDelivery as dbUpdateDelivery,
} from "./notificationStore.js";

const USERS_DIR = resolveConfiguredPath(process.env["USERS_DIR"], "../users");
const MAX_OUTBOX_ITEMS = 250;
const WHATSAPP_GRAPH_VERSION = process.env["WHATSAPP_GRAPH_VERSION"] ?? "v17.0";

const DEFAULT_NOTIFICATION_PREFERENCES: NotificationPreferences = NotificationPreferencesSchema.parse({
  primaryChannel: "telegram",
  enabledChannels: {
    telegram: true,
    web: true,
    whatsapp: false,
  },
  categories: {
    dailyBriefs: true,
    reportRuns: true,
    marketNews: true,
  },
});

function profilePath(userId: string): string {
  return path.join(USERS_DIR, userId, "profile.json");
}

function outboxPath(userId: string): string {
  return path.join(USERS_DIR, userId, "feed", "notifications.json");
}

export async function getNotificationPreferences(
  userId: string
): Promise<NotificationPreferences> {
  const connectivity = await getUserChannelConnectivity(userId);
  try {
    const raw = await fs.readFile(profilePath(userId), "utf-8");
    const parsed = JSON.parse(raw) as { notifications?: unknown };
    const result = NotificationPreferencesSchema.safeParse(parsed.notifications);
    const base = result.success ? result.data : DEFAULT_NOTIFICATION_PREFERENCES;
    return {
      ...base,
      primaryChannel:
        base.primaryChannel === "telegram" && !connectivity.telegram.connected
          ? "web"
          : base.primaryChannel === "whatsapp" && !connectivity.whatsapp.connected
            ? "web"
            : base.primaryChannel,
      enabledChannels: {
        ...base.enabledChannels,
        telegram: base.enabledChannels.telegram && connectivity.telegram.connected,
        whatsapp: base.enabledChannels.whatsapp && connectivity.whatsapp.connected,
      },
    };
  } catch {
    return {
      ...DEFAULT_NOTIFICATION_PREFERENCES,
      enabledChannels: {
        ...DEFAULT_NOTIFICATION_PREFERENCES.enabledChannels,
        telegram: connectivity.telegram.connected,
        whatsapp: false,
      },
      primaryChannel: connectivity.telegram.connected ? "telegram" : "web",
    };
  }
}

export async function setNotificationPreferences(
  userId: string,
  preferences: NotificationPreferences
): Promise<NotificationPreferences> {
  const validated = NotificationPreferencesSchema.parse(preferences);
  const connectivity = await getUserChannelConnectivity(userId);
  const nextPrimaryChannel =
    validated.primaryChannel === "telegram" && !connectivity.telegram.connected
      ? "web"
      : validated.primaryChannel === "whatsapp" && !connectivity.whatsapp.connected
        ? "web"
        : validated.primaryChannel;
  const normalized = {
    ...validated,
    primaryChannel: nextPrimaryChannel,
    enabledChannels: {
      ...validated.enabledChannels,
      telegram: validated.enabledChannels.telegram && connectivity.telegram.connected,
      whatsapp: validated.enabledChannels.whatsapp && connectivity.whatsapp.connected,
    },
  } satisfies NotificationPreferences;

  const target = profilePath(userId);
  let profile: Record<string, unknown> = {};
  try {
    profile = JSON.parse(await fs.readFile(target, "utf-8")) as Record<string, unknown>;
  } catch {}

  profile["notifications"] = normalized;
  await fs.writeFile(target, JSON.stringify(profile, null, 2), "utf-8");
  return normalized;
}

export interface NotificationEnvelope {
  id: string;
  userId: string;
  category: "daily_brief" | "report" | "market_news";
  title: string;
  body: string;
  ticker: string | null;
  batchId: string | null;
  channel: "telegram" | "web" | "whatsapp";
  createdAt: string;
  delivered: boolean;
  deliveredAt: string | null;
  readAt: string | null;
  error: string | null;
}

export interface NotificationPublishRequest extends SemanticNotificationRequest {
  userId: string;
}

function categoryEnabled(preferences: NotificationPreferences, category: NotificationEnvelope["category"]): boolean {
  if (category === "daily_brief") return preferences.categories.dailyBriefs;
  if (category === "report") return preferences.categories.reportRuns;
  return preferences.categories.marketNews;
}

function redactLogMessage(value: unknown, maxLength = 180): string {
  return String(value instanceof Error ? value.message : value ?? "unknown error")
    .replace(/bot\d+:[A-Za-z0-9_-]+/g, "bot<redacted>")
    .replace(/https:\/\/api\.telegram\.org\/[^\s]+/g, "https://api.telegram.org/<redacted>")
    .replace(/Bearer\s+\S+/gi, "Bearer <redacted>")
    .replace(/\s+/g, " ")
    .slice(0, maxLength);
}

function logNotificationEvent(
  level: "info" | "warn",
  fields: Record<string, string | number | boolean | null | string[]>
): void {
  logger[level](JSON.stringify({ event: "notification_publication", ...fields }));
}

function renderRecordContent(
  composed: ComposedNotification,
  channel: NotificationEnvelope["channel"]
): Pick<NotificationEnvelope, "category" | "title" | "body" | "ticker" | "batchId"> {
  if (channel === "telegram") {
    const telegram = renderTelegramNotification(composed);
    return {
      category: composed.category,
      title: composed.title,
      body: telegram.text,
      ticker: composed.ticker,
      batchId: composed.batchId,
    };
  }

  const web = renderWebNotification(composed);
  return {
    category: web.category,
    title: web.title,
    body: web.body,
    ticker: web.ticker,
    batchId: web.batchId,
  };
}

async function readOutbox(userId: string): Promise<NotificationEnvelope[]> {
  try {
    const raw = await fs.readFile(outboxPath(userId), "utf-8");
    return JSON.parse(raw) as NotificationEnvelope[];
  } catch {
    return [];
  }
}

async function writeOutbox(userId: string, items: NotificationEnvelope[]): Promise<void> {
  const filePath = outboxPath(userId);
  await fs.mkdir(path.dirname(filePath), { recursive: true });
  await fs.writeFile(filePath, JSON.stringify(items.slice(0, MAX_OUTBOX_ITEMS), null, 2), "utf-8");
}

async function appendOutboxRecord(record: NotificationEnvelope): Promise<void> {
  const current = await readOutbox(record.userId);
  await writeOutbox(record.userId, [record, ...current]);
}

async function updateOutboxRecord(
  userId: string,
  notificationId: string,
  update: Partial<Pick<NotificationEnvelope, "delivered" | "deliveredAt" | "readAt" | "error">>
): Promise<void> {
  const current = await readOutbox(userId);
  const next = current.map((item) => (item.id === notificationId ? { ...item, ...update } : item));
  await writeOutbox(userId, next);
}

async function getTelegramTarget(userId: string): Promise<{ botToken: string; chatId: string } | null> {
  try {
    const { isApplicationDatabaseConfigured, getApplicationDataSource } = await import("../db/applicationDataSource.js");
    if (!isApplicationDatabaseConfigured()) return null;
    const ds = await getApplicationDataSource();
    const [bindingRows, secretRows] = await Promise.all([
      ds.query(
        `SELECT channel_identifier FROM channel_bindings
          WHERE user_id = $1 AND channel = 'telegram' AND unbound_at IS NULL
          LIMIT 1`,
        [userId]
      ) as Promise<Array<{ channel_identifier: string }>>,
      ds.query(
        `SELECT ciphertext FROM encrypted_secrets
          WHERE user_id = $1 AND secret_kind = 'telegram_bot_token'
          LIMIT 1`,
        [userId]
      ) as Promise<Array<{ ciphertext: Buffer }>>,
    ]);
    const chatId = bindingRows[0]?.channel_identifier;
    const botToken = secretRows[0]?.ciphertext?.toString("utf-8");
    if (!chatId || !botToken) return null;
    return { botToken, chatId };
  } catch {
    return null;
  }
}

async function deliverTelegram(record: NotificationEnvelope): Promise<{ delivered: boolean; error: string | null }> {
  const target = await getTelegramTarget(record.userId);
  if (!target) {
    return { delivered: false, error: "telegram target not configured" };
  }

  try {
    const response = await fetch(`https://api.telegram.org/bot${target.botToken}/sendMessage`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        chat_id: target.chatId,
        text: record.body,
        disable_web_page_preview: true,
      }),
    });

    if (!response.ok) {
      const body = await response.text();
      return { delivered: false, error: `telegram send failed: ${redactLogMessage(body, 140)}` };
    }

    return { delivered: true, error: null };
  } catch (err) {
    return {
      delivered: false,
      error: redactLogMessage(err, 140),
    };
  }
}

async function deliverWhatsApp(record: NotificationEnvelope): Promise<{ delivered: boolean; error: string | null }> {
  const target = await getStoredWhatsAppConnection(record.userId);
  if (!target) {
    return { delivered: false, error: "whatsapp target not configured" };
  }

  try {
    const response = await fetch(
      `https://graph.facebook.com/${WHATSAPP_GRAPH_VERSION}/${target.phoneNumberId}/messages`,
      {
        method: "POST",
        headers: {
          Authorization: `Bearer ${target.accessToken}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          messaging_product: "whatsapp",
          recipient_type: "individual",
          to: target.recipientPhone,
          type: "text",
          text: {
            preview_url: false,
            body: `${record.title}\n${record.body}`.slice(0, 4096),
          },
        }),
      }
    );

    if (!response.ok) {
      const body = await response.text();
      return { delivered: false, error: `whatsapp send failed: ${body.slice(0, 140)}` };
    }

    return { delivered: true, error: null };
  } catch (err) {
    return {
      delivered: false,
      error: err instanceof Error ? err.message.slice(0, 140) : "whatsapp send failed",
    };
  }
}

function buildCandidateChannels(
  preferences: NotificationPreferences,
  connectivity: Awaited<ReturnType<typeof getUserChannelConnectivity>>
): Array<NotificationEnvelope["channel"]> {
  const connectedChannels: Array<NotificationEnvelope["channel"]> = [];

  if (preferences.enabledChannels.web && connectivity.web.connected) connectedChannels.push("web");
  if (preferences.enabledChannels.telegram && connectivity.telegram.connected) connectedChannels.push("telegram");
  if (preferences.enabledChannels.whatsapp && connectivity.whatsapp.connected) connectedChannels.push("whatsapp");

  if (preferences.primaryChannel === "none") return connectedChannels;

  if (connectedChannels.includes(preferences.primaryChannel as NotificationEnvelope["channel"])) {
    connectedChannels.sort((left, right) => {
      if (left === preferences.primaryChannel) return -1;
      if (right === preferences.primaryChannel) return 1;
      return 0;
    });
  }

  return connectedChannels;
}

export async function publishNotification(
  request: NotificationPublishRequest
): Promise<NotificationEnvelope[]> {
  const composed = composeNotification(request);
  const preferences = await getNotificationPreferences(request.userId);
  if (!categoryEnabled(preferences, composed.category)) {
    logNotificationEvent("info", {
      decision: "category_disabled",
      userId: request.userId,
      semanticKind: composed.kind,
      category: composed.category,
      batchId: composed.batchId,
      channels: [],
    });
    return [];
  }

  if (composed.batchId) {
    const existing = (await readOutbox(request.userId)).filter(
      (item) => item.category === composed.category && item.batchId === composed.batchId
    );
    if (existing.length > 0) {
      logNotificationEvent("info", {
        decision: "duplicate_batch",
        userId: request.userId,
        semanticKind: composed.kind,
        category: composed.category,
        batchId: composed.batchId,
        channels: existing.map((item) => item.channel),
      });
      return existing;
    }
  }

  const connectivity = await getUserChannelConnectivity(request.userId);
  const candidateChannels = buildCandidateChannels(preferences, connectivity);

  const createdAt = new Date().toISOString();
  const records = candidateChannels.map<NotificationEnvelope>((channel) => ({
    id: `ntf_${Date.now()}_${channel}_${Math.random().toString(16).slice(2, 8)}`,
    userId: request.userId,
    createdAt,
    delivered: channel === "web",
    deliveredAt: channel === "web" ? createdAt : null,
    readAt: null,
    error: channel === "web" ? null : "pending delivery",
    channel,
    ...renderRecordContent(composed, channel),
  }));

  const deliveryOutcomes: string[] = [];

  for (const record of records) {
    await appendOutboxRecord(record);

    // Phase 1 dual-write to Postgres. Failures are logged but do not block
    // the legacy JSON path which is still source of truth.
    try {
      await dbInsertNotification({
        id: record.id,
        userId: record.userId,
        category: record.category,
        channel: record.channel,
        title: record.title,
        body: record.body,
        ticker: record.ticker,
        batchId: record.batchId,
        delivered: record.delivered,
        deliveredAt: record.deliveredAt,
        readAt: record.readAt,
        error: record.error,
      });
    } catch (err) {
      const message = redactLogMessage(err);
      logNotificationEvent("warn", {
        decision: "dual_write_failed",
        userId: record.userId,
        notificationId: record.id,
        semanticKind: composed.kind,
        category: record.category,
        channel: record.channel,
        batchId: record.batchId,
        error: message,
      });
    }

    if (record.channel === "telegram") {
      const result = await deliverTelegram(record);
      const deliveredAtIso = result.delivered ? new Date().toISOString() : null;
      deliveryOutcomes.push(`telegram:${result.delivered ? "delivered" : "failed"}`);
      await updateOutboxRecord(record.userId, record.id, {
        delivered: result.delivered,
        deliveredAt: deliveredAtIso,
        error: result.error,
      });
      try {
        await dbUpdateDelivery(record.userId, record.id, {
          delivered: result.delivered,
          deliveredAt: deliveredAtIso,
          error: result.error,
        });
      } catch (err) {
        const message = redactLogMessage(err);
        logNotificationEvent("warn", {
          decision: "dual_write_delivery_failed",
          userId: record.userId,
          notificationId: record.id,
          semanticKind: composed.kind,
          category: record.category,
          channel: record.channel,
          batchId: record.batchId,
          error: message,
        });
      }
    }
    if (record.channel === "whatsapp") {
      const result = await deliverWhatsApp(record);
      const deliveredAtIso = result.delivered ? new Date().toISOString() : null;
      deliveryOutcomes.push(`whatsapp:${result.delivered ? "delivered" : "failed"}`);
      await updateOutboxRecord(record.userId, record.id, {
        delivered: result.delivered,
        deliveredAt: deliveredAtIso,
        error: result.error,
      });
      try {
        await dbUpdateDelivery(record.userId, record.id, {
          delivered: result.delivered,
          deliveredAt: deliveredAtIso,
          error: result.error,
        });
      } catch (err) {
        const message = redactLogMessage(err);
        logNotificationEvent("warn", {
          decision: "dual_write_delivery_failed",
          userId: record.userId,
          notificationId: record.id,
          semanticKind: composed.kind,
          category: record.category,
          channel: record.channel,
          batchId: record.batchId,
          error: message,
        });
      }
    }
  }

  logNotificationEvent("info", {
    decision: records.length > 0 ? "published" : "no_channels",
    userId: request.userId,
    semanticKind: composed.kind,
    category: composed.category,
    batchId: composed.batchId,
    channels: candidateChannels,
    deliveryOutcome: deliveryOutcomes.join(",") || (records.length > 0 ? "web:delivered" : "none"),
  });
  return records;
}

export async function listNotifications(
  userId: string,
  options?: { limit?: number; channel?: NotificationEnvelope["channel"] | null; unreadOnly?: boolean }
): Promise<NotificationEnvelope[]> {
  const items = await readOutbox(userId);
  const filtered = items.filter((item) => {
    if (options?.channel && item.channel !== options.channel) return false;
    if (options?.unreadOnly && item.readAt !== null) return false;
    return true;
  });
  return filtered.slice(0, options?.limit ?? 50);
}

export async function markNotificationsRead(userId: string, ids: string[]): Promise<number> {
  if (ids.length === 0) return 0;
  const current = await readOutbox(userId);
  const idSet = new Set(ids);
  let updated = 0;
  const now = new Date().toISOString();
  const next = current.map((item) => {
    if (!idSet.has(item.id) || item.readAt !== null) return item;
    updated += 1;
    return { ...item, readAt: now };
  });
  await writeOutbox(userId, next);
  return updated;
}

export { DEFAULT_NOTIFICATION_PREFERENCES };

import express from "express";
import { lookupByChannelId, setConversationId } from "../services/channelBindingStore.js";
import { agentChat } from "../services/chat/agentChat.js";
import { logger } from "../services/logger.js";
import { completeChannelBinding } from "./channels.js";
import { getApplicationDataSource, isApplicationDatabaseConfigured } from "../db/applicationDataSource.js";

/**
 * Telegram webhook — Phase 6, task 6.2.
 *
 * Spec: design.md §9.2; D1.1–D1.4.
 *
 * Thin transport: verify secret → resolve channel binding → call agentChat
 * → deliver reply. No slash-command parsing (D1.4). No content branching.
 *
 * The strict refuse-to-start guard for TELEGRAM_SECRET lands in Phase 9.
 * For now: log + reject malformed requests.
 */

const router = express.Router();

const TELEGRAM_MAX_MESSAGE_LENGTH = 4096;

function splitMessage(text: string, maxLen: number): string[] {
  if (text.length <= maxLen) return [text];
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > 0) {
    chunks.push(remaining.slice(0, maxLen));
    remaining = remaining.slice(maxLen);
  }
  return chunks;
}

async function deliverTelegramReply(
  botToken: string,
  chatId: string,
  text: string
): Promise<void> {
  const chunks = splitMessage(text, TELEGRAM_MAX_MESSAGE_LENGTH);
  for (const chunk of chunks) {
    try {
      const response = await fetch(
        `https://api.telegram.org/bot${botToken}/sendMessage`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            chat_id: chatId,
            text: chunk,
            parse_mode: "Markdown",
            disable_web_page_preview: true,
          }),
        }
      );
      if (!response.ok) {
        const body = await response.text();
        logger.warn(`Telegram delivery failed: ${body.slice(0, 200)}`);
      }
    } catch (err) {
      logger.warn(`Telegram delivery error: ${(err as Error).message}`);
    }
  }
}

async function getBotTokenForUser(userId: string): Promise<string | null> {
  if (!isApplicationDatabaseConfigured()) return null;
  try {
    const ds = await getApplicationDataSource();
    const rows = await ds.query(
      `SELECT ciphertext FROM encrypted_secrets
        WHERE user_id = $1 AND secret_kind = 'telegram_bot_token'
        LIMIT 1`,
      [userId]
    ) as Array<{ ciphertext: Buffer }>;
    const row = rows[0];
    if (!row) return null;
    // Phase 1 identity encryption: ciphertext IS the plaintext
    return row.ciphertext.toString("utf-8");
  } catch {
    return null;
  }
}

router.post("/telegram/webhook", async (req, res) => {
  // 1. Verify secret token (Phase 9 adds the strict startup guard)
  const secret = req.headers["x-telegram-bot-api-secret-token"];
  if (process.env["TELEGRAM_SECRET"] && secret !== process.env["TELEGRAM_SECRET"]) {
    if (isApplicationDatabaseConfigured()) {
      try {
        const ds = await getApplicationDataSource();
        await ds.query(
          `INSERT INTO admin_audit_log
             (actor_admin_id, action_type, target_user_id, args_json, result_status, request_id, ip_address, occurred_at)
           VALUES ('telegram_webhook', 'telegram_webhook_signature_failed', NULL, '{}'::jsonb, 'rejected', gen_random_uuid()::text, $1, NOW())`,
          [req.ip ?? null]
        );
      } catch { /* audit failure must not block */ }
    }
    res.status(200).json({ ok: true }); // Telegram requires 200
    return;
  }

  try {
    const update = req.body;
    const message = update?.message;
    if (!message?.text || !message?.chat?.id) {
      res.json({ ok: true });
      return;
    }

    const chatId = String(message.chat.id);
    const text = (message.text as string).trim();

    // 2. Handle channel-binding connect code
    const connectMatch = text.match(/^(?:\/connect\s+|connect\s+)([A-Fa-f0-9]{6})$/i);
    if (connectMatch) {
      const code = connectMatch[1]!;
      const result = await completeChannelBinding(code, "telegram", chatId);
      if (result.success && result.userId) {
        const botToken = await getBotTokenForUser(result.userId);
        if (botToken) {
          await deliverTelegramReply(botToken, chatId, result.message);
        }
      }
      res.json({ ok: true });
      return;
    }

    // 3. Resolve channel binding (D1.1)
    const binding = await lookupByChannelId("telegram", chatId);
    if (!binding) {
      if (isApplicationDatabaseConfigured()) {
        try {
          const ds = await getApplicationDataSource();
          await ds.query(
            `INSERT INTO admin_audit_log
               (actor_admin_id, action_type, target_user_id, args_json, result_status, request_id, ip_address, occurred_at)
             VALUES ('telegram_webhook', 'unknown_channel', NULL, $1::jsonb, 'rejected', gen_random_uuid()::text, $2, NOW())`,
            [JSON.stringify({ chatId }), req.ip ?? null]
          );
        } catch { /* audit failure must not block */ }
      }
      res.json({ ok: true });
      return;
    }

    // 4. Resolve or create conversation id (D1.2)
    let conversationId = binding.conversationId ?? undefined;

    // 5. Call agentChat (D1.2)
    const result = await agentChat({
      userId: binding.userId,
      text,
      channel: "telegram",
      ...(conversationId ? { conversationId } : {}),
    });

    // Persist conversation id on the binding for future messages
    if (!binding.conversationId && result.conversationId) {
      await setConversationId("telegram", chatId, result.conversationId);
    }

    // 6. Deliver reply (D1.3) — length truncation only
    const botToken = await getBotTokenForUser(binding.userId);
    if (botToken) {
      await deliverTelegramReply(botToken, chatId, result.replyText);
    } else {
      logger.warn(`No bot token found for user ${binding.userId}, cannot deliver Telegram reply`);
    }

    res.json({ ok: true });
  } catch (err) {
    logger.error("Telegram webhook error", { err });
    res.json({ ok: true }); // Always 200 to Telegram
  }
});

