import { promises as fs } from "fs";
import path from "path";
import { resolveConfiguredPath } from "./paths.js";
import { WhatsAppConnectionSchema, type WhatsAppConnection } from "../schemas/channels.js";
import { listBindingsForUser, unbindChannel } from "./channelBindingStore.js";

const USERS_DIR = resolveConfiguredPath(process.env["USERS_DIR"], "../users");

export interface ChannelStatus {
  connected: boolean;
  target: string | null;
}

export interface UserChannelConnectivity {
  telegram: ChannelStatus;
  whatsapp: ChannelStatus;
  web: ChannelStatus;
}

function profilePath(userId: string): string {
  return path.join(USERS_DIR, userId, "profile.json");
}

async function readProfileRecord(userId: string): Promise<Record<string, unknown>> {
  try {
    const raw = await fs.readFile(profilePath(userId), "utf-8");
    return JSON.parse(raw) as Record<string, unknown>;
  } catch {
    return {};
  }
}

async function writeProfileRecord(userId: string, profile: Record<string, unknown>): Promise<void> {
  await fs.writeFile(profilePath(userId), JSON.stringify(profile, null, 2), "utf-8");
}

export async function getStoredWhatsAppConnection(userId: string): Promise<WhatsAppConnection | null> {
  const profile = await readProfileRecord(userId);
  const connection = (profile.channelConnections as { whatsapp?: unknown } | undefined)?.whatsapp;
  if (!connection) return null;

  try {
    return WhatsAppConnectionSchema.parse(connection);
  } catch {
    return null;
  }
}

export async function getUserChannelConnectivity(userId: string): Promise<UserChannelConnectivity> {
  const [bindings, whatsappConnection] = await Promise.all([
    listBindingsForUser(userId),
    getStoredWhatsAppConnection(userId),
  ]);

  const telegramBinding = bindings.find((b) => b.channel === "telegram");

  return {
    telegram: {
      connected: telegramBinding !== undefined,
      target: telegramBinding?.channelIdentifier ?? null,
    },
    whatsapp: {
      connected: whatsappConnection !== null,
      target: whatsappConnection?.recipientPhone ?? null,
    },
    web: {
      connected: true,
      target: "in-app",
    },
  };
}

export async function connectUserTelegramChannel(
  userId: string,
  _botToken: string,
  telegramChatId: string
): Promise<void> {
  const profile = await readProfileRecord(userId);
  profile.telegramChatId = telegramChatId;
  await writeProfileRecord(userId, profile);
}

export async function disconnectUserTelegramChannel(userId: string): Promise<void> {
  const bindings = await listBindingsForUser(userId);
  const telegramBinding = bindings.find((b) => b.channel === "telegram");
  if (telegramBinding) {
    await unbindChannel("telegram", telegramBinding.channelIdentifier);
  }

  const profile = await readProfileRecord(userId);
  delete profile.telegramChatId;
  await writeProfileRecord(userId, profile);
}

export async function connectUserWhatsAppChannel(
  userId: string,
  connection: WhatsAppConnection
): Promise<void> {
  const profile = await readProfileRecord(userId);
  const currentConnections =
    typeof profile.channelConnections === "object" && profile.channelConnections !== null
      ? (profile.channelConnections as Record<string, unknown>)
      : {};

  profile.channelConnections = {
    ...currentConnections,
    whatsapp: connection,
  };

  await writeProfileRecord(userId, profile);
}

export async function disconnectUserWhatsAppChannel(userId: string): Promise<void> {
  const profile = await readProfileRecord(userId);
  const currentConnections =
    typeof profile.channelConnections === "object" && profile.channelConnections !== null
      ? ({ ...(profile.channelConnections as Record<string, unknown>) } as Record<string, unknown>)
      : {};

  delete currentConnections.whatsapp;
  profile.channelConnections = currentConnections;
  await writeProfileRecord(userId, profile);
}

import { createLogger, format, transports } from "winston";
import path from "path";
import fs from "fs";

const logDir = path.resolve("logs");
if (!fs.existsSync(logDir)) {
  fs.mkdirSync(logDir, { recursive: true });
}

const logLevel = process.env["LOG_LEVEL"] ?? "info";

export const logger = createLogger({
  level: logLevel,
  format: format.combine(
    format.timestamp({ format: "YYYY-MM-DD HH:mm:ss" }),
    format.errors({ stack: true }),
    format.printf(({ level, message, timestamp, stack }) => {
      if (stack) {
        return `${timestamp} [${level.toUpperCase()}] ${message}\n${stack}`;
      }
      return `${timestamp} [${level.toUpperCase()}] ${message}`;
    })
  ),
  transports: [
    new transports.Console({
      format: format.combine(format.colorize(), format.timestamp()),
    }),
    new transports.File({
      filename: path.join(logDir, "app.log"),
      format: format.uncolorize(),
      maxsize: 10 * 1024 * 1024,
      maxFiles: 5,
    }),
  ],
});

import { getApplicationDataSource, isApplicationDatabaseConfigured } from "../db/applicationDataSource.js";
import type { ChannelBindingChannel } from "../db/entities/ChannelBindingEntity.js";
import { unwrapMutationRows } from "./dbUtils.js";

export type { ChannelBindingChannel } from "../db/entities/ChannelBindingEntity.js";

/**
 * Channel-binding store — Telegram chat / WhatsApp phone → user_id (§4.16,
 * D1.1, D2.3). Used by the transports to resolve inbound webhook traffic to
 * a Clawd user, and by the chat agent to pick a stable conversationId.
 */

export interface ChannelBindingRecord {
  channel: ChannelBindingChannel;
  channelIdentifier: string;
  userId: string;
  conversationId: string | null;
  boundAt: string;
  unboundAt: string | null;
}

export interface BindChannelInput {
  channel: ChannelBindingChannel;
  channelIdentifier: string;
  userId: string;
  conversationId?: string | null;
}

interface Row {
  channel: ChannelBindingChannel;
  channel_identifier: string;
  user_id: string;
  conversation_id: string | null;
  bound_at: Date | string;
  unbound_at: Date | string | null;
}

function toIso(value: Date | string | null): string | null {
  if (value === null) return null;
  const d = value instanceof Date ? value : new Date(value);
  return Number.isNaN(d.getTime()) ? null : d.toISOString();
}

function fromRow(row: Row): ChannelBindingRecord {
  return {
    channel: row.channel,
    channelIdentifier: row.channel_identifier,
    userId: row.user_id,
    conversationId: row.conversation_id,
    boundAt: toIso(row.bound_at) ?? new Date().toISOString(),
    unboundAt: toIso(row.unbound_at),
  };
}

const SELECT_COLUMNS = `channel, channel_identifier, user_id, conversation_id, bound_at, unbound_at`;

/**
 * Idempotent upsert. If a row exists for (channel, channelIdentifier),
 * its `unbound_at` is cleared and `user_id` is rewritten — supporting the
 * "user rebinds the same chat to a different account" path. Caller should
 * gate this on a confirmation code (the `/connect` flow in §9.4).
 */
export async function bindChannel(input: BindChannelInput): Promise<ChannelBindingRecord> {
  if (!isApplicationDatabaseConfigured()) {
    throw new Error("bindChannel requires the application database");
  }
  const ds = await getApplicationDataSource();
  const rows = (await ds.query(
    `INSERT INTO channel_bindings
       (channel, channel_identifier, user_id, conversation_id, bound_at, unbound_at)
     VALUES ($1, $2, $3, $4, NOW(), NULL)
     ON CONFLICT (channel, channel_identifier) DO UPDATE SET
       user_id = EXCLUDED.user_id,
       conversation_id = EXCLUDED.conversation_id,
       bound_at = NOW(),
       unbound_at = NULL
     RETURNING ${SELECT_COLUMNS}`,
    [input.channel, input.channelIdentifier, input.userId, input.conversationId ?? null]
  )) as Row[];
  return fromRow(rows[0]!);
}

/**
 * Lookup the active binding (unbound_at IS NULL) for an inbound channel
 * identifier. Returns null when no active binding is found.
 */
export async function lookupByChannelId(
  channel: ChannelBindingChannel,
  channelIdentifier: string
): Promise<ChannelBindingRecord | null> {
  if (!isApplicationDatabaseConfigured()) return null;
  const ds = await getApplicationDataSource();
  const rows = (await ds.query(
    `SELECT ${SELECT_COLUMNS} FROM channel_bindings
      WHERE channel = $1 AND channel_identifier = $2 AND unbound_at IS NULL
      LIMIT 1`,
    [channel, channelIdentifier]
  )) as Row[];
  return rows[0] ? fromRow(rows[0]) : null;
}

/** All active bindings for a user across all channels. */
export async function listBindingsForUser(userId: string): Promise<ChannelBindingRecord[]> {
  if (!isApplicationDatabaseConfigured()) return [];
  const ds = await getApplicationDataSource();
  const rows = (await ds.query(
    `SELECT ${SELECT_COLUMNS} FROM channel_bindings
      WHERE user_id = $1 AND unbound_at IS NULL
      ORDER BY channel ASC, bound_at DESC`,
    [userId]
  )) as Row[];
  return rows.map(fromRow);
}

/** Soft-unbind by stamping `unbound_at`. Inbound webhooks then return null. */
export async function unbindChannel(
  channel: ChannelBindingChannel,
  channelIdentifier: string
): Promise<boolean> {
  if (!isApplicationDatabaseConfigured()) return false;
  const ds = await getApplicationDataSource();
  const raw = await ds.query(
    `UPDATE channel_bindings
        SET unbound_at = NOW()
      WHERE channel = $1 AND channel_identifier = $2 AND unbound_at IS NULL
      RETURNING channel`,
    [channel, channelIdentifier]
  );
  return unwrapMutationRows<{ channel: string }>(raw).length > 0;
}

/** Persist or update the conversation id for a binding (D1.2 / D2.3). */
export async function setConversationId(
  channel: ChannelBindingChannel,
  channelIdentifier: string,
  conversationId: string
): Promise<void> {
  if (!isApplicationDatabaseConfigured()) return;
  const ds = await getApplicationDataSource();
  await ds.query(
    `UPDATE channel_bindings
        SET conversation_id = $3
      WHERE channel = $1 AND channel_identifier = $2 AND unbound_at IS NULL`,
    [channel, channelIdentifier, conversationId]
  );
}

import "reflect-metadata";
import { promises as fs } from "fs";
import path from "path";
import { DataSource } from "typeorm";
import { JobEntitySchema } from "./entities/JobEntity.js";
import { ModelTierAssignmentEntitySchema } from "./entities/ModelTierAssignmentEntity.js";
import { ObservabilityRequestEntitySchema } from "./entities/ObservabilityRequestEntity.js";
import { StepLifecycleEventEntitySchema } from "./entities/StepLifecycleEventEntity.js";
import { StepWorkItemEntitySchema } from "./entities/StepWorkItemEntity.js";
import { TickerWorkItemEntitySchema } from "./entities/TickerWorkItemEntity.js";
import { TrackedAssetEntitySchema } from "./entities/TrackedAssetEntity.js";
import { UserPointsBudgetEntitySchema } from "./entities/UserPointsBudgetEntity.js";
import { UserEntitySchema } from "./entities/UserEntity.js";
import { StrategyEntitySchema } from "./entities/StrategyEntity.js";
import { ReportBatchEntitySchema } from "./entities/ReportBatchEntity.js";
import { ReportIndexEntitySchema } from "./entities/ReportIndexEntity.js";
import { NotificationEntitySchema } from "./entities/NotificationEntity.js";
import { EscalationHistoryEntitySchema } from "./entities/EscalationHistoryEntity.js";
import { VerdictActionEntitySchema } from "./entities/VerdictActionEntity.js";
import { TickerSnoozeEntitySchema } from "./entities/TickerSnoozeEntity.js";
import { PortfolioRiskSnapshotEntitySchema } from "./entities/PortfolioRiskSnapshotEntity.js";
import { AdminAuditLogEntitySchema } from "./entities/AdminAuditLogEntity.js";
import { MigrationArchiveEntitySchema } from "./entities/MigrationArchiveEntity.js";
import { FeatureFlagEntitySchema } from "./entities/FeatureFlagEntity.js";
import { ChannelBindingEntitySchema } from "./entities/ChannelBindingEntity.js";
import { EncryptedSecretEntitySchema } from "./entities/EncryptedSecretEntity.js";
import { ConversationEntitySchema } from "./entities/ConversationEntity.js";
import { ConversationTurnEntitySchema } from "./entities/ConversationTurnEntity.js";
import { ToolCallEntitySchema } from "./entities/ToolCallEntity.js";
import { OutputFilterEventEntitySchema } from "./entities/OutputFilterEventEntity.js";
import { PositionTransactionEntitySchema } from "./entities/PositionTransactionEntity.js";
import { CorporateActionEntitySchema } from "./entities/CorporateActionEntity.js";
import { PilotFeatureReviewEntitySchema } from "./entities/PilotFeatureReviewEntity.js";
import { logger } from "../services/logger.js";

const APP_DATABASE_URL =
  process.env["APP_DATABASE_URL"] ??
  process.env["OBSERVABILITY_DATABASE_URL"] ??
  "";
const APP_DATABASE_DDL_PATH =
  process.env["APP_DATABASE_DDL_PATH"] ??
  process.env["OBSERVABILITY_DDL_PATH"] ??
  path.resolve(process.cwd(), "../db/application_postgres.sql");

let dataSource: DataSource | null = null;
let ddlApplied = false;

export function isApplicationDatabaseConfigured(): boolean {
  return APP_DATABASE_URL.length > 0;
}

function buildDataSource(): DataSource {
  if (!APP_DATABASE_URL) {
    throw new Error("APP_DATABASE_URL is required");
  }

  return new DataSource({
    type: "postgres",
    url: APP_DATABASE_URL,
    entities: [
      JobEntitySchema,
      ModelTierAssignmentEntitySchema,
      ObservabilityRequestEntitySchema,
      StepLifecycleEventEntitySchema,
      StepWorkItemEntitySchema,
      TickerWorkItemEntitySchema,
      TrackedAssetEntitySchema,
      UserPointsBudgetEntitySchema,
      // Phase 1 (design.md §4.1–4.17):
      UserEntitySchema,
      StrategyEntitySchema,
      ReportBatchEntitySchema,
      ReportIndexEntitySchema,
      NotificationEntitySchema,
      EscalationHistoryEntitySchema,
      VerdictActionEntitySchema,
      TickerSnoozeEntitySchema,
      PortfolioRiskSnapshotEntitySchema,
      AdminAuditLogEntitySchema,
      MigrationArchiveEntitySchema,
      FeatureFlagEntitySchema,
      ChannelBindingEntitySchema,
      EncryptedSecretEntitySchema,
      // Phase 5 (design.md §4.11–4.12):
      ConversationEntitySchema,
      ConversationTurnEntitySchema,
      ToolCallEntitySchema,
      OutputFilterEventEntitySchema,
      // Phase 7 (design.md §4.6–4.7):
      PositionTransactionEntitySchema,
      CorporateActionEntitySchema,
      // Pilot admin review state:
      PilotFeatureReviewEntitySchema,
    ],
    synchronize: false,
    logging: false,
  });
}

async function applyDdl(ds: DataSource): Promise<void> {
  if (ddlApplied) return;
  const ddl = await fs.readFile(APP_DATABASE_DDL_PATH, "utf-8");
  await ds.query(ddl);
  ddlApplied = true;
}

export async function getApplicationDataSource(): Promise<DataSource> {
  if (!dataSource) {
    dataSource = buildDataSource();
  }

  if (!dataSource.isInitialized) {
    await dataSource.initialize();
    await applyDdl(dataSource);
    logger.info("Application PostgreSQL data source initialized");
  }

  return dataSource;
}

export async function closeApplicationDataSource(): Promise<void> {
  if (dataSource?.isInitialized) {
    await dataSource.destroy();
  }
  dataSource = null;
  ddlApplied = false;
}

